SELECT tl.library_id, tl.title, tl.description, u.nickname,
tl.view_count, tl.import_count, tl.created_at,
false AS is_owner
FROM travel_library tl
JOIN users u ON tl.user_id = u.user_id

    tl.user_id != #{userId}

        AND tl.title LIKE CONCAT('%', #{keyword}, '%')


ORDER BY tl.created_at DESC
LIMIT #{limitSize}
OFFSET #{offset}

SELECT tl.library_id, tl.title, tl.description, u.nickname,
tl.view_count, tl.import_count, tl.created_at,
true AS is_owner
FROM travel_library tl
JOIN users u ON tl.user_id = u.user_id

    tl.user_id = #{userId}

        AND tl.title LIKE CONCAT('%', #{keyword}, '%')


ORDER BY tl.created_at DESC
LIMIT #{limitSize}
OFFSET #{offset}

SELECT from_item_id, to_item_id, transport, move_time, cost
FROM library_routes
WHERE library_id = #{libraryId}

SELECT library_id, user_id, title, description, view_count, import_count
FROM travel_library
WHERE library_id = #{libraryId}
